Greater than: false
Less than: false
Greater than or equal to: true
Less than or equal to: true
Logical AND: false
Logical OR: true
Logical NOT: true
Bitwise AND: 2
Bitwise OR: 14
Bitwise XOR: 12
Bitwise NOT: -11
Left shift: 20
Right shift: 5
Unsigned right shift: 5
